	@Test
	void q9LikeOptionalKeepsRepeatedBridgeRowsForFollowingOptional(@TempDir File dataDir) throws Exception {
		String previousLegacy = System.setProperty(LmdbQueryOptimizerPipeline.LEGACY_SKETCH_OPTIMIZER_PROPERTY,
				"true");
		String previousCascades = System.setProperty(LmdbCascadesOptimizer.MODE_PROPERTY, "off");
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,ospc,psoc,posc");
		LmdbStore store = new LmdbStore(dataDir, config);
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			loadQ9LikeFanout(repository);
			store.getBackingStore().getSketchBasedJoinEstimator().rebuild();
			LmdbPlannerAwait.awaitSketchesReady(store);

			try (SailRepositoryConnection connection = repository.getConnection()) {
				String query = String.join("\n",
						"SELECT (COUNT(*) AS ?count) WHERE {",
						"  ?org <urn:test:q9:department> ?department .",
						"  ?department <urn:test:q9:makesOffer> ?offer .",
						"  ?offer <urn:test:q9:itemOffered> ?work .",
						"  ?work <urn:test:q9:about> ?topic .",
						"  ?topic <urn:test:q9:mainEntityOfPage> ?page .",
						"  ?person <urn:test:q9:memberOf> ?org .",
						"  ?person <urn:test:q9:type> <urn:test:q9:Person> .",
						"  OPTIONAL {",
						"    ?page <urn:test:q9:event> ?event .",
						"    ?event <urn:test:q9:position> ?eventPosition .",
						"    FILTER(?eventPosition IN (1, 2, 3, 4))",
						"    BIND(?eventPosition AS ?eventBucket)",
						"  }",
						"  OPTIONAL {",
						"    ?org <urn:test:q9:employee> ?employee .",
						"  }",
						"}");

				try (TupleQueryResult result = connection.prepareTupleQuery(query).evaluate()) {
					assertTrue(result.hasNext(), "Expected count result");
					assertEquals(EXPECTED_FINAL_ROWS, ((Literal) result.next().getValue("count")).longValue());
				}

				Explanation explanation = connection.prepareTupleQuery(query).explain(Explanation.Level.Telemetry);
				LeftJoin eventOptional = findOptionalWithBridgeProduct((TupleExpr) explanation.tupleExpr());
				StatementPattern typePattern = findStatementPattern((TupleExpr) explanation.tupleExpr(), TYPE,
						"_const_person");
				StatementPattern employeePattern = findStatementPattern((TupleExpr) explanation.tupleExpr(), EMPLOYEE,
						"employee");
				assertNotNull(eventOptional, explanation::toString);
				assertNotNull(typePattern, explanation::toString);
				assertNotNull(employeePattern, explanation::toString);
				assertEquals(EXPECTED_TYPED_PREFIX_ROWS, typePattern.getResultSizeActual(), explanation::toString);
				assertEquals(EXPECTED_EVENT_OPTIONAL_ROWS,
						eventOptional.getDoubleMetricPlanned("plannedOptionalBridgeProductRows"),
						EXPECTED_EVENT_OPTIONAL_ROWS * 0.25d,
						"Event OPTIONAL estimate must combine page bridge fanout with the repeated typed prefix: "
								+ explanation);
				assertTrue(
						employeePattern.getDoubleMetricPlanned(
								"plannedRepeatedInvocations") >= EXPECTED_EVENT_OPTIONAL_ROWS,
						"Following employee OPTIONAL must be costed from event-expanded rows: " + explanation);
				assertEquals(EXPECTED_FINAL_ROWS, employeePattern.getResultSizeEstimate(),
						EXPECTED_FINAL_ROWS * 0.25d,
						"Following employee OPTIONAL estimate should track repeated output rows: " + explanation);
				assertEquals("lmdb-bound-join-product",
						employeePattern.getStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE),
						"Following employee OPTIONAL should use duplicate-corrected tuple sketch product even when "
								+ "earlier OPTIONALs introduced finite binding values: " + explanation);
				assertEquals(EXPECTED_FINAL_ROWS,
						employeePattern.getDoubleMetricPlanned(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS),
						EXPECTED_FINAL_ROWS * 0.25d,
						"Following employee OPTIONAL planned cardinality should include rows per repeated lookup: "
								+ explanation);
				assertTrue(
						employeePattern.getDoubleMetricPlanned(
								TelemetryMetricNames.PLANNED_WORK_ROWS) >= EXPECTED_FINAL_ROWS,
						"Following employee OPTIONAL work must cover repeated emitted rows: " + explanation);
			}
		} finally {
			repository.shutDown();
			restoreProperty(LmdbQueryOptimizerPipeline.LEGACY_SKETCH_OPTIMIZER_PROPERTY, previousLegacy);
			restoreProperty(LmdbCascadesOptimizer.MODE_PROPERTY, previousCascades);
		}
	}

