	private static void loadQ9LikeFanout(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			for (int orgIndex = 0; orgIndex < ORG_COUNT; orgIndex++) {
				Resource org = VF.createIRI("urn:test:q9:org:" + orgIndex);
				for (int departmentIndex = 0; departmentIndex < DEPARTMENTS_PER_ORG; departmentIndex++) {
					Resource department = VF.createIRI("urn:test:q9:department:" + orgIndex + ":"
							+ departmentIndex);
					connection.add(org, DEPARTMENT, department);
					for (int offerIndex = 0; offerIndex < OFFERS_PER_DEPARTMENT; offerIndex++) {
						Resource offer = VF.createIRI("urn:test:q9:offer:" + orgIndex + ":" + departmentIndex
								+ ":" + offerIndex);
						Resource work = VF.createIRI("urn:test:q9:work:" + orgIndex + ":" + departmentIndex + ":"
								+ offerIndex);
						Resource topic = VF.createIRI("urn:test:q9:topic:" + orgIndex + ":" + departmentIndex
								+ ":" + offerIndex);
						Resource page = VF.createIRI("urn:test:q9:page:" + orgIndex + ":" + departmentIndex
								+ ":" + offerIndex);
						connection.add(department, MAKES_OFFER, offer);
						connection.add(offer, ITEM_OFFERED, work);
						connection.add(work, ABOUT, topic);
						connection.add(topic, MAIN_ENTITY_OF_PAGE, page);
						for (int eventIndex = 0; eventIndex < EVENTS_PER_PAGE; eventIndex++) {
							Resource event = VF.createIRI("urn:test:q9:event:" + orgIndex + ":" + departmentIndex
									+ ":" + offerIndex + ":" + eventIndex);
							connection.add(page, EVENT, event);
							connection.add(event, POSITION, VF.createLiteral(eventIndex + 1));
						}
					}
				}
				for (int personIndex = 0; personIndex < PERSONS_PER_ORG; personIndex++) {
					Resource person = VF.createIRI("urn:test:q9:person:" + orgIndex + ":" + personIndex);
					connection.add(person, MEMBER_OF, org);
					connection.add(person, TYPE, PERSON);
				}
				for (int employeeIndex = 0; employeeIndex < EMPLOYEES_PER_ORG; employeeIndex++) {
					connection.add(org, EMPLOYEE,
							VF.createIRI("urn:test:q9:employee:" + orgIndex + ":" + employeeIndex));
				}
			}
			connection.commit();
		}
	}

	private static void loadUnselectedEventPositionNoise(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			for (int pageIndex = 0; pageIndex < NOISE_PAGE_COUNT; pageIndex++) {
				Resource page = VF.createIRI("urn:test:q9:noise-page:" + pageIndex);
				for (int eventIndex = 0; eventIndex < NOISE_EVENTS_PER_PAGE; eventIndex++) {
					Resource event = VF.createIRI("urn:test:q9:noise-event:" + pageIndex + ":" + eventIndex);
					connection.add(page, EVENT, event);
					connection.add(event, POSITION, VF.createLiteral(1000 + eventIndex));
				}
			}
			connection.commit();
		}
	}

	private static StatementPattern findStatementPattern(TupleExpr tupleExpr, IRI predicate, String objectName) {
		List<StatementPattern> matches = new ArrayList<>(1);
		tupleExpr.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(StatementPattern node) {
				if (predicate.equals(node.getPredicateVar().getValue())
						&& (objectName.equals(node.getObjectVar().getName())
								|| objectName.equals("_const_person")
										&& PERSON.equals(node.getObjectVar().getValue()))) {
					matches.add(node);
				}
			}
		});
		return matches.isEmpty() ? null : matches.getFirst();
	}

	private static LeftJoin findOptionalWithBridgeProduct(TupleExpr tupleExpr) {
		List<LeftJoin> matches = new ArrayList<>(1);
		tupleExpr.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(LeftJoin node) {
				if (node.getDoubleMetricPlanned("plannedOptionalBridgeProductRows") >= 0.0d) {
					matches.add(node);
				}
				super.meet(node);
			}
		});
		return matches.isEmpty() ? null : matches.getFirst();
	}

	private static void restoreProperty(String name, String previousValue) {
		if (previousValue == null) {
			System.clearProperty(name);
		} else {
			System.setProperty(name, previousValue);
		}
	}
